#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<long long> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    long long k; cin >> k;

    long long prefix_sum = 0;
    unordered_map<long long, int> seen;
    seen[0] = -1;
    int max_length = 0;

    for(int i = 0; i < n; i++){
        prefix_sum += nums[i];
        if(seen.find(prefix_sum - k) != seen.end()){
            max_length = max(max_length, i - seen[prefix_sum - k]);
        }
        if(seen.find(prefix_sum) == seen.end()){
            seen[prefix_sum] = i;
        }
    }

    cout << max_length << endl;
    return 0;
}
